import{_ as i,c as e,o as t,a1 as l}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"平台功能：模型與配額 | opencode-antigravity-auth","description":"了解 Antigravity Auth 的模型類型和雙配額系統。掌握模型選擇、Thinking 配置和 Google Search 方法，優化配額使用。","frontmatter":{"title":"平台功能：模型與配額 | opencode-antigravity-auth","sidebarTitle":"解鎖雙配額系統","subtitle":"平台功能：模型與配額","description":"了解 Antigravity Auth 的模型類型和雙配額系統。掌握模型選擇、Thinking 配置和 Google Search 方法，優化配額使用。","order":2},"headers":[],"relativePath":"zh-tw/NoeFabris/opencode-antigravity-auth/platforms/index.md","filePath":"zh-tw/NoeFabris/opencode-antigravity-auth/platforms/index.md"}'),n={name:"zh-tw/NoeFabris/opencode-antigravity-auth/platforms/index.md"};function o(r,a,h,d,s,u){return t(),e("div",null,[...a[0]||(a[0]=[l('<h1 id="平台功能" tabindex="-1">平台功能 <a class="header-anchor" href="#平台功能" aria-label="Permalink to &quot;平台功能&quot;">​</a></h1><p>本章節幫助你深入了解 Antigravity Auth 插件支援的模型、配額系統和平台特性。你將學會選擇合適的模型、配置 Thinking 能力、啟用 Google Search 以及最大化配額利用率。</p><h2 id="前置條件" tabindex="-1">前置條件 <a class="header-anchor" href="#前置條件" aria-label="Permalink to &quot;前置條件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">開始前請確認</p><p>在學習本章節之前，請確保你已完成：</p><ul><li><a href="./../../zh-tw/NoeFabris/opencode-antigravity-auth/start/quick-install/">快速安裝</a>：完成插件安裝和首次認證</li><li><a href="./../../zh-tw/NoeFabris/opencode-antigravity-auth/start/first-request/">首次請求</a>：成功發起第一個模型請求</li></ul></div><h2 id="學習路徑" tabindex="-1">學習路徑 <a class="header-anchor" href="#學習路徑" aria-label="Permalink to &quot;學習路徑&quot;">​</a></h2><p>按以下順序學習，循序漸進掌握平台功能：</p><h3 id="_1-可用模型" tabindex="-1">1. <a href="./available-models/">可用模型</a> <a class="header-anchor" href="#_1-可用模型" aria-label="Permalink to &quot;1. [可用模型](./available-models/)&quot;">​</a></h3><p>了解所有可用的模型及其變體配置</p><ul><li>認識 Claude Opus 4.5、Sonnet 4.5 和 Gemini 3 Pro/Flash</li><li>理解 Antigravity 和 Gemini CLI 兩個配額池的模型分佈</li><li>掌握 <code>--variant</code> 參數的使用方法</li></ul><h3 id="_2-雙配額系統" tabindex="-1">2. <a href="./dual-quota-system/">雙配額系統</a> <a class="header-anchor" href="#_2-雙配額系統" aria-label="Permalink to &quot;2. [雙配額系統](./dual-quota-system/)&quot;">​</a></h3><p>理解 Antigravity 和 Gemini CLI 雙配額池的工作原理</p><ul><li>了解每個帳戶如何擁有兩個獨立的 Gemini 配額池</li><li>啟用自動 fallback 配置，實現配額翻倍</li><li>顯式指定模型使用特定配額池</li></ul><h3 id="_3-google-search-grounding" tabindex="-1">3. <a href="./google-search-grounding/">Google Search Grounding</a> <a class="header-anchor" href="#_3-google-search-grounding" aria-label="Permalink to &quot;3. [Google Search Grounding](./google-search-grounding/)&quot;">​</a></h3><p>為 Gemini 模型啟用 Google Search，提升事實準確性</p><ul><li>讓 Gemini 能夠搜尋即時網路資訊</li><li>調節搜尋閾值，控制搜尋頻率</li><li>根據任務需求選擇合適的配置</li></ul><h3 id="_4-thinking-模型" tabindex="-1">4. <a href="./thinking-models/">Thinking 模型</a> <a class="header-anchor" href="#_4-thinking-模型" aria-label="Permalink to &quot;4. [Thinking 模型](./thinking-models/)&quot;">​</a></h3><p>掌握 Claude 和 Gemini 3 Thinking 模型的配置和使用</p><ul><li>配置 Claude 的 thinking budget</li><li>使用 Gemini 3 的 thinking level（minimal/low/medium/high）</li><li>理解 interleaved thinking 和思考塊保留策略</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>完成本章節後，你可以繼續學習：</p><ul><li><a href="./../advanced/multi-account-setup/">多帳戶配置</a>：配置多個 Google 帳戶，實現配額池化和負載平衡</li><li><a href="./../advanced/account-selection-strategies/">帳戶選擇策略</a>：掌握 sticky、round-robin、hybrid 三種策略的最佳實踐</li><li><a href="./../advanced/configuration-guide/">配置指南</a>：掌握所有配置選項，按需定制插件行為</li></ul>',21)])])}const p=i(n,[["render",o]]);export{g as __pageData,p as default};
